/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Formats notification payloads as short text messages and sends them
 * to a configured phone number via a pluggable transport.
 *
 * In production the transport would use Twilio / AWS SNS / etc.
 * The default transport stores messages in memory for testing.
 */

import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationChannel,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

export interface SmsConfig {
  /** The sender phone number or short code (e.g. "+15551234567"). */
  fromNumber: string;
  /** Maximum delivery attempts before giving up. */
  maxRetries: number;
}

const DEFAULT_SMS_CONFIG: SmsConfig = {
  fromNumber: '',
  maxRetries: 2,
};

// ---------------------------------------------------------------------------
// SMS message type
// ---------------------------------------------------------------------------

export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

// ---------------------------------------------------------------------------
// Transport abstraction
// ---------------------------------------------------------------------------

/**
 * Pluggable transport that actually delivers the SMS.
 * The default implementation stores messages in memory (for testing).
 * In production, swap this for a Twilio / SNS transport.
 */
export interface SmsTransport {
  send(message: SmsMessage): Promise<void>;
}

/**
 * Record of a sent SMS — includes the message and timestamp.
 */
export interface SentSms {
  message: SmsMessage;
  sentAt: Date;
}

/**
 * In-memory transport — stores sent messages for inspection in tests.
 */
export class InMemorySmsTransport implements SmsTransport {
  private deliveredMessages: SentSms[] = [];

  async send(message: SmsMessage): Promise<void> {
    this.deliveredMessages.push({
      message,
      sentAt: new Date(),
    });
  }

  getDeliveredMessages(): SentSms[] {
    return [...this.deliveredMessages];
  }

  clear(): void {
    this.deliveredMessages = [];
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

function validateRecipient(recipient: string): string | null {
  if (!recipient || !PHONE_REGEX.test(recipient)) {
    return `Invalid phone number: ${recipient}`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Adapter
// ---------------------------------------------------------------------------

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';

  private logger = new Logger('SmsAdapter');
  private config: SmsConfig;
  private transport: SmsTransport;

  constructor(config?: Partial<SmsConfig>, transport?: SmsTransport) {
    this.config = { ...DEFAULT_SMS_CONFIG, ...config };
    this.transport = transport ?? new InMemorySmsTransport();
  }

  /**
   * Format the notification payload as a short text message and send it.
   *
   * Per the NotificationAdapter contract this method never throws.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    try {
      // 1. Validate from number is configured
      if (!this.config.fromNumber) {
        const error = 'SMS from number is not configured';
        this.logger.error(error);
        return { success: false, error };
      }

      // 2. Validate recipient phone number
      const validationError = validateRecipient(payload.recipient);
      if (validationError) {
        this.logger.error(validationError);
        return { success: false, error: validationError };
      }

      // 3. Format message
      const message = this.formatMessage(payload);

      // 4. Attempt delivery with retries
      let lastError: string | undefined;
      for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
        try {
          await this.transport.send(message);
          this.logger.info(
            `SMS delivered to ${payload.recipient}: ${payload.notificationType}`,
          );
          return { success: true };
        } catch (err: unknown) {
          lastError = err instanceof Error ? err.message : 'Transport error';
          this.logger.warn(
            `Delivery attempt ${attempt + 1} failed for ${payload.recipient}: ${lastError}`,
          );
        }
      }

      this.logger.error(
        `All delivery attempts exhausted for ${payload.recipient}: ${lastError}`,
      );
      return { success: false, error: lastError };
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Unknown SMS error';
      this.logger.error(`Unexpected error sending to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Format a NotificationPayload into a short SMS text message.
   * SMS messages are kept concise — subject + body, no HTML.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    return {
      to: payload.recipient,
      from: this.config.fromNumber,
      body: `${payload.subject}: ${payload.body}`,
    };
  }

  // -----------------------------------------------------------------------
  // Convenience accessors (primarily for testing)
  // -----------------------------------------------------------------------

  /**
   * Get all SMS messages sent through this adapter.
   * Only works when using InMemorySmsTransport.
   */
  getSentMessages(): SentSms[] {
    if (this.transport instanceof InMemorySmsTransport) {
      return this.transport.getDeliveredMessages();
    }
    return [];
  }

  /**
   * Clear sent message history.
   * Only works when using InMemorySmsTransport.
   */
  clearSentMessages(): void {
    if (this.transport instanceof InMemorySmsTransport) {
      this.transport.clear();
    }
  }

  /**
   * Get the current configuration (useful for testing).
   */
  getConfig(): Readonly<SmsConfig> {
    return { ...this.config };
  }
}

