import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsNotificationAdapter,
  InMemorySmsTransport,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  SmsMessage,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'sms',
    notificationType: 'order_confirmation',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('SmsNotificationAdapter', () => {
  let adapter: SmsNotificationAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsNotificationAdapter(
      { fromNumber: '+15559876543' },
      transport,
    );
  });

  // -----------------------------------------------------------------------
  // Basic send
  // -----------------------------------------------------------------------

  it('should deliver an SMS successfully', async () => {
    const result = await adapter.send(makePayload());

    expect(result.success).toBe(true);
    const sent = adapter.getSentMessages();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.message.to).toBe('+15551234567');
    expect(sent[0]?.message.from).toBe('+15559876543');
  });

  it('should format message as subject + body', async () => {
    await adapter.send(makePayload());

    const sent = adapter.getSentMessages();
    const msg = sent[0]?.message;
    expect(msg?.body).toBe(
      'Order Confirmation: order-1: Your order has been placed. Items: Widget x2. Total: $20.00',
    );
  });

  // -----------------------------------------------------------------------
  // From number validation
  // -----------------------------------------------------------------------

  it('should fail when from number is not configured', async () => {
    adapter = new SmsNotificationAdapter({ fromNumber: '' }, transport);
    const result = await adapter.send(makePayload());

    expect(result.success).toBe(false);
    expect(result.error).toBe('SMS from number is not configured');
    expect(adapter.getSentMessages()).toHaveLength(0);
  });

  it('should fail when from number is undefined (default)', async () => {
    adapter = new SmsNotificationAdapter(undefined, transport);
    const result = await adapter.send(makePayload());

    expect(result.success).toBe(false);
    expect(result.error).toBe('SMS from number is not configured');
  });

  // -----------------------------------------------------------------------
  // Recipient validation
  // -----------------------------------------------------------------------

  it('should fail for invalid phone number (no plus prefix)', async () => {
    const result = await adapter.send(makePayload({ recipient: '15551234567' }));

    expect(result.success).toBe(false);
    expect(result.error).toBe('Invalid phone number: 15551234567');
  });

  it('should fail for empty recipient', async () => {
    const result = await adapter.send(makePayload({ recipient: '' }));

    expect(result.success).toBe(false);
    expect(result.error).toBe('Invalid phone number: ');
  });

  it('should fail for non-numeric phone number', async () => {
    const result = await adapter.send(makePayload({ recipient: '+abc' }));

    expect(result.success).toBe(false);
    expect(result.error).toContain('Invalid phone number');
  });

  it('should accept valid international phone numbers', async () => {
    const result = await adapter.send(makePayload({ recipient: '+442071234567' }));

    expect(result.success).toBe(true);
  });

  // -----------------------------------------------------------------------
  // Notification types
  // -----------------------------------------------------------------------

  it('should format order_status_update messages', async () => {
    await adapter.send(
      makePayload({
        notificationType: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Status changed from pending to confirmed.',
      }),
    );

    const sent = adapter.getSentMessages();
    expect(sent[0]?.message.body).toContain('pending to confirmed');
  });

  it('should format user_welcome messages', async () => {
    await adapter.send(
      makePayload({
        notificationType: 'user_welcome',
        subject: 'Welcome!',
        body: 'Welcome aboard, Alice!',
      }),
    );

    const sent = adapter.getSentMessages();
    expect(sent[0]?.message.body).toBe('Welcome!: Welcome aboard, Alice!');
  });

  it('should format user_updated messages', async () => {
    await adapter.send(
      makePayload({
        notificationType: 'user_updated',
        subject: 'Account Updated',
        body: 'Your email has been changed.',
      }),
    );

    const sent = adapter.getSentMessages();
    expect(sent[0]?.message.body).toContain('Account Updated');
  });

  // -----------------------------------------------------------------------
  // Retry logic
  // -----------------------------------------------------------------------

  it('should retry on transport failure', async () => {
    let attempts = 0;
    const failingTransport: SmsTransport = {
      async send() {
        attempts++;
        if (attempts < 3) {
          throw new Error('Connection timeout');
        }
      },
    };

    adapter = new SmsNotificationAdapter(
      { fromNumber: '+15559876543', maxRetries: 2 },
      failingTransport,
    );
    const result = await adapter.send(makePayload());

    expect(result.success).toBe(true);
    expect(attempts).toBe(3); // 1 initial + 2 retries
  });

  it('should return failure after exhausting retries', async () => {
    const failingTransport: SmsTransport = {
      async send() {
        throw new Error('Permanent failure');
      },
    };

    adapter = new SmsNotificationAdapter(
      { fromNumber: '+15559876543', maxRetries: 1 },
      failingTransport,
    );
    const result = await adapter.send(makePayload());

    expect(result.success).toBe(false);
    expect(result.error).toBe('Permanent failure');
  });

  it('should succeed on first attempt when no errors', async () => {
    let attempts = 0;
    const countingTransport: SmsTransport = {
      async send() {
        attempts++;
      },
    };

    adapter = new SmsNotificationAdapter(
      { fromNumber: '+15559876543', maxRetries: 3 },
      countingTransport,
    );
    await adapter.send(makePayload());

    expect(attempts).toBe(1);
  });

  // -----------------------------------------------------------------------
  // Configuration
  // -----------------------------------------------------------------------

  it('should expose config via getConfig', () => {
    adapter = new SmsNotificationAdapter({
      fromNumber: '+15559876543',
      maxRetries: 5,
    });

    const config = adapter.getConfig();
    expect(config.fromNumber).toBe('+15559876543');
    expect(config.maxRetries).toBe(5);
  });

  // -----------------------------------------------------------------------
  // Clearing
  // -----------------------------------------------------------------------

  it('should clear sent messages', async () => {
    await adapter.send(makePayload());
    expect(adapter.getSentMessages()).toHaveLength(1);

    adapter.clearSentMessages();
    expect(adapter.getSentMessages()).toHaveLength(0);
  });

  // -----------------------------------------------------------------------
  // Channel
  // -----------------------------------------------------------------------

  it('should report sms channel', () => {
    expect(adapter.channel).toBe('sms');
  });

  // -----------------------------------------------------------------------
  // formatMessage
  // -----------------------------------------------------------------------

  it('should expose formatMessage for direct use', () => {
    const formatted = adapter.formatMessage(makePayload());

    expect(formatted.to).toBe('+15551234567');
    expect(formatted.from).toBe('+15559876543');
    expect(formatted.body).toContain('Order Confirmation');
  });
});

describe('InMemorySmsTransport', () => {
  it('should store and retrieve delivered messages', async () => {
    const transport = new InMemorySmsTransport();

    await transport.send({
      to: '+15551234567',
      from: '+15559876543',
      body: 'Hello!',
    });

    const messages = transport.getDeliveredMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0]?.message.to).toBe('+15551234567');
  });

  it('should clear delivered messages', async () => {
    const transport = new InMemorySmsTransport();

    await transport.send({
      to: '+15551234567',
      from: '+15559876543',
      body: 'Hello!',
    });

    transport.clear();
    expect(transport.getDeliveredMessages()).toHaveLength(0);
  });
});

